const GENERATED_HEADER = """
# Generated by gen/run.jl — do not edit manually.
"""

function _write_file(path::AbstractString, content::AbstractString)
    mkpath(dirname(path))
    open(path, "w") do io
        write(io, content)
    end
    return path
end

function emit_enums(api::Dict{String,Any}, path::AbstractString)
    lines = String[GENERATED_HEADER, "\n"]
    for enum in api["enums"]
        name = enum["name"]
        push!(lines, "@enum $name::Int32 begin")
        for value in enum["values"]
            push!(lines, "    $(value["name"]) = $(value["value"])")
        end
        push!(lines, "end\n")
    end
    _write_file(path, join(lines, '\n'))
end

function emit_handles(api::Dict{String,Any}, path::AbstractString)
    lines = String[GENERATED_HEADER, "\nconst ANARIHandle = Ptr{Cvoid}\n"]
    for opaque in api["opaqueTypes"]
        push!(lines, "const $(opaque["name"]) = ANARIHandle")
    end
    for typedef in get(api, "functionTypedefs", Any[])
        push!(lines, "const $(typedef["name"]) = Ptr{Cvoid}")
    end
    push!(lines, "")
    _write_file(path, join(lines, '\n'))
end

function emit_structs(api::Dict{String,Any}, path::AbstractString)
    lines = String[GENERATED_HEADER, "\n"]
    for st in api["structs"]
        push!(lines, "struct $(st["name"])")
        for member in st["members"]
            jtype = julia_struct_member_type(member["type"])
            push!(lines, "    $(member["name"])::$jtype")
        end
        push!(lines, "end\n")
    end
    _write_file(path, join(lines, '\n'))
end

function _libanari_export_names(api::Dict{String,Any})
    names = String["libanari", "ANARIHandle"]
    for fun in api["functions"]
        push!(names, fun["name"])
    end
    for opaque in api["opaqueTypes"]
        push!(names, opaque["name"])
    end
    for typedef in get(api, "functionTypedefs", Any[])
        push!(names, typedef["name"])
    end
    for st in api["structs"]
        push!(names, st["name"])
    end
    for enum in api["enums"]
        push!(names, enum["name"])
        for value in enum["values"]
            push!(names, value["name"])
        end
    end
    append!(names, [
        "DataTypeInfo", "DATATYPE_INFO", "datatype_info", "julia_type", "c_type",
        "datatype_size", "datatype_components", "is_normalized",
        "ParameterSpec", "PropertySpec",
        "OBJECT_SUBTYPES", "OBJECT_PARAMETERS", "OBJECT_PROPERTIES", "ATTRIBUTES",
        "object_subtypes", "parameter_specs", "property_specs", "parameter_spec", "is_required",
    ])
    return unique(names)
end

function _emit_function(lines, fun::Dict{String,Any})
    name = fun["name"]
    args = fun["arguments"]
    ret = fun["returnType"]

    arg_names = [julia_argname(arg["name"]) for arg in args]
    arg_sig = join(arg_names, ", ")
    arg_ccall = join(
        ("$(julia_argname(arg["name"]))::$(julia_ctype(arg["type"]))" for arg in args),
        ", ",
    )

    push!(lines, "function $name($arg_sig)")
    if ret == "void"
        push!(lines, "    @ccall libanari.$name($arg_ccall)::Cvoid")
        push!(lines, "    return nothing")
    else
        push!(lines, "    return @ccall libanari.$name($arg_ccall)::$(julia_ctype(ret))")
    end
    push!(lines, "end")
end

function emit_libanari(api::Dict{String,Any}, path::AbstractString)
    lines = String[
        GENERATED_HEADER,
        "",
        "module LibANARI",
        "",
        "using ANARI_SDK_jll",
        "",
        "const libanari = ANARI_SDK_jll.libanari",
        "",
        "include(\"enums.jl\")",
        "include(\"handles.jl\")",
        "include(\"structs.jl\")",
        "include(\"datatypes.jl\")",
        "",
    ]

    for fun in api["functions"]
        _emit_function(lines, fun)
        push!(lines, "")
    end

    push!(lines, "include(\"objects.jl\")")
    push!(lines, "")
    for chunk in Iterators.partition(_libanari_export_names(api), 8)
        push!(lines, "export " * join(chunk, ", "))
    end
    push!(lines, "")
    push!(lines, "end # module")
    _write_file(path, join(lines, '\n'))
end

function emit_generated_module(out_dir::AbstractString)
    path = joinpath(out_dir, "Generated.jl")
    content = join([
        GENERATED_HEADER,
        "",
        "module Generated",
        "",
        "include(\"LibANARI.jl\")",
        "",
        "using .LibANARI",
        "",
        "export LibANARI",
        "export DataTypeInfo, DATATYPE_INFO",
        "export datatype_info, julia_type, c_type, datatype_size, datatype_components, is_normalized",
        "export ParameterSpec, PropertySpec",
        "export OBJECT_SUBTYPES, OBJECT_PARAMETERS, OBJECT_PROPERTIES, ATTRIBUTES",
        "export object_subtypes, parameter_specs, property_specs, parameter_spec, is_required",
        "",
        "",
        "end # module",
        "",
    ], '\n')
    _write_file(path, content)
end

function emit_core(api::Dict{String,Any}, out_dir::AbstractString)
    emit_enums(api, joinpath(out_dir, "enums.jl"))
    emit_handles(api, joinpath(out_dir, "handles.jl"))
    emit_structs(api, joinpath(out_dir, "structs.jl"))
    emit_libanari(api, joinpath(out_dir, "LibANARI.jl"))
end
